}

export interface MatrixData {
  rows: number;
  columns: number;
  values: number[][];
}

export type MatrixOperation =
  | "add"
  | "subtract"
  | "multiply"
  | "transpose"
  | "determinant"
  | "inverse";

export interface MatrixOperationRequest {
  operation: MatrixOperation;
