export interface ConditionDiagnostics {
  pivotStrategy: "none" | "partial";
  conditionEstimate?: number;
  singular: boolean;
}

export interface MatrixOperationResult {
  operation: MatrixOperation;
  matrix?: MatrixData;
  scalar?: string;
  diagnostics?: ConditionDiagnostics;
