import type { CalculatorSettings, WorkspaceState } from "@core/contracts";
import type { HistoryEntry } from "../features/history/model";
import type { MemoryRegister } from "../features/memory/model";
import {
  HISTORY_SCHEMA_VERSION,
  MEMORY_SCHEMA_VERSION,
  SETTINGS_SCHEMA_VERSION,
  WORKSPACE_SCHEMA_VERSION,
  createDefaultHistoryDocument,
  createDefaultMemoryDocument,
  createDefaultSettingsDocument,
  createDefaultWorkspaceDocument,
  parsePersistedHistory,
  parsePersistedMemory,
  parsePersistedSettings,
  parsePersistedWorkspace,
  type PersistedHistoryDocument,
  type PersistedMemoryDocument,
  type PersistedSettingsDocument,
  type PersistedWorkspaceDocument
} from "./schema";
import { sanitizeCalculatorSettings } from "../features/settings/model";
import { sanitizeWorkspaceState } from "../app/workspaceDrafts";

const STORAGE_KEYS = {
  settings: "calculator.settings.v1",
  workspace: "calculator.workspace.v1",
  history: "calculator.history.v1",
  memory: "calculator.memory.v1"
} as const;

export interface StorageLike {
  getItem(key: string): string | null;
  setItem(key: string, value: string): void;
  removeItem(key: string): void;
}

export interface PersistenceSnapshot {
  settings: PersistedSettingsDocument;
  workspace: PersistedWorkspaceDocument;
  history: PersistedHistoryDocument;
  memory: PersistedMemoryDocument;
}

type Clock = () => string;

function readDocument<TDocument>(
  storage: StorageLike,
  key: string,
  parse: (value: unknown) => TDocument | null,
  fallback: () => TDocument
): TDocument {
  const raw = storage.getItem(key);
  if (raw === null) {
    return fallback();
  }

  try {
    const parsed = JSON.parse(raw) as unknown;
    return parse(parsed) ?? fallback();
  } catch {
    return fallback();
  }
}

function writeDocument(storage: StorageLike, key: string, value: unknown): void {
  storage.setItem(key, JSON.stringify(value));
}

export function createMemoryStorage(): StorageLike {
  const values = new Map<string, string>();

  return {
    getItem(key) {
      return values.get(key) ?? null;
    },
    setItem(key, value) {
      values.set(key, value);
    },
    removeItem(key) {
      values.delete(key);
    }
  };
}

export function getBrowserStorage(): StorageLike {
  if (typeof window === "undefined") {
    return createMemoryStorage();
  }

  try {
    return window.localStorage;
  } catch {
    return createMemoryStorage();
  }
}

export function createCalculatorPersistence(storage: StorageLike, now: Clock = () => new Date().toISOString()) {
  return {
    loadSnapshot(): PersistenceSnapshot {
      return {
        settings: readDocument(storage, STORAGE_KEYS.settings, parsePersistedSettings, createDefaultSettingsDocument),
        workspace: readDocument(storage, STORAGE_KEYS.workspace, parsePersistedWorkspace, createDefaultWorkspaceDocument),
        history: readDocument(storage, STORAGE_KEYS.history, parsePersistedHistory, createDefaultHistoryDocument),
        memory: readDocument(storage, STORAGE_KEYS.memory, parsePersistedMemory, createDefaultMemoryDocument)
      };
    },
    saveSettings(payload: CalculatorSettings): PersistedSettingsDocument {
      const document: PersistedSettingsDocument = {
        version: SETTINGS_SCHEMA_VERSION,
        updatedAt: now(),
        payload: sanitizeCalculatorSettings(payload)
      };
      writeDocument(storage, STORAGE_KEYS.settings, document);
      return document;
    },
    saveWorkspace(payload: WorkspaceState): PersistedWorkspaceDocument {
      const document: PersistedWorkspaceDocument = {
        version: WORKSPACE_SCHEMA_VERSION,
        updatedAt: now(),
        payload: sanitizeWorkspaceState(payload)
      };
      writeDocument(storage, STORAGE_KEYS.workspace, document);
      return document;
    },
    saveHistory(entries: HistoryEntry[]): PersistedHistoryDocument {
      const document: PersistedHistoryDocument = {
        version: HISTORY_SCHEMA_VERSION,
        updatedAt: now(),
        payload: {
          entries
        }
      };
      writeDocument(storage, STORAGE_KEYS.history, document);
      return document;
    },
    saveMemory(registers: MemoryRegister[]): PersistedMemoryDocument {
      const document: PersistedMemoryDocument = {
        version: MEMORY_SCHEMA_VERSION,
        updatedAt: now(),
        payload: {
          registers
        }
      };
      writeDocument(storage, STORAGE_KEYS.memory, document);
      return document;
    }
  };
}

import type { MatrixData, WorkspaceState } from "@core/contracts";

function clampDimension(value: number): number {
  if (!Number.isFinite(value)) {
    return 2;
  }

  return Math.min(6, Math.max(2, Math.round(value)));
}

function normalizeMatrixCell(value: unknown): number {
  return typeof value === "number" && Number.isFinite(value) ? value : 0;
}

export function createDefaultMatrixData(): MatrixData {
  return {
    rows: 2,
    columns: 2,
    values: [
      [1, 0],
      [0, 1]
    ]
  };
}

export function resizeMatrix(matrix: MatrixData, rows: number, columns: number): MatrixData {
  const nextRows = clampDimension(rows);
  const nextColumns = clampDimension(columns);
  const nextValues = Array.from({ length: nextRows }, (_, rowIndex) =>
    Array.from({ length: nextColumns }, (_, columnIndex) => normalizeMatrixCell(matrix.values[rowIndex]?.[columnIndex]))
  );

  return {
    rows: nextRows,
    columns: nextColumns,
    values: nextValues
  };
}

export function updateMatrixCell(
  matrix: MatrixData,
  rowIndex: number,
  columnIndex: number,
  value: number
): MatrixData {
  const next = resizeMatrix(matrix, matrix.rows, matrix.columns);
  next.values[rowIndex]![columnIndex] = Number.isFinite(value) ? value : 0;
  return next;
}

export function createDefaultWorkspaceState(): WorkspaceState {
  return {
    activeTool: "calculate",
    expressionInput: "",
    matrix: {
      left: createDefaultMatrixData(),
      right: createDefaultMatrixData()
    },
    solver: {
      expression: "",
      method: "newton",
      initialGuess: "0",
      bracketLower: "-1",
      bracketUpper: "1"
    },
    numerical: {
      expression: "",
      tool: "differentiate",
      point: "0",
      intervalStart: "0",
      intervalEnd: "1"
    }
  };
}

export function sanitizeWorkspaceState(workspace: WorkspaceState): WorkspaceState {
  const rightMatrix = workspace.matrix.right
    ? resizeMatrix(workspace.matrix.right, workspace.matrix.right.rows, workspace.matrix.right.columns)
    : createDefaultMatrixData();

  return {
    activeTool: workspace.activeTool,
    expressionInput: workspace.expressionInput,
    matrix: {
      left: resizeMatrix(workspace.matrix.left, workspace.matrix.left.rows, workspace.matrix.left.columns),
      right: rightMatrix
    },
    solver: {
      expression: workspace.solver.expression,
      method: workspace.solver.method,
      initialGuess: workspace.solver.initialGuess,
      bracketLower: workspace.solver.bracketLower,
      bracketUpper: workspace.solver.bracketUpper
    },
    numerical: {
      expression: workspace.numerical.expression,
      tool: workspace.numerical.tool,
      point: workspace.numerical.point,
      intervalStart: workspace.numerical.intervalStart,
      intervalEnd: workspace.numerical.intervalEnd
    }
  };
}

import type { CalculatorSettings, ComputationIssue, WorkspaceState, WorkspaceToolId } from "@core/contracts";
import type { HistoryEntry, HistoryModeMetadata } from "../features/history/model";
import type { MemoryRegister } from "../features/memory/model";

export interface WorkspacePresentation {
  tool: WorkspaceToolId;
  title: string;
  detail: string;
  value: string;
  issues: ComputationIssue[];
}

function formatMatrixLabel(rows: number, columns: number): string {
  return `${rows} x ${columns}`;
}

export function buildModeMetadata(settings: CalculatorSettings): HistoryModeMetadata {
  return {
    backend: settings.numeric.backend,
    angleMode: settings.numeric.angleMode,
    displayMode: settings.numeric.displayMode,
    displayPrecision: settings.numeric.displayPrecision
  };
}

export function summarizeWorkspace(workspace: WorkspaceState): WorkspacePresentation {
  switch (workspace.activeTool) {
    case "calculate":
      return {
        tool: "calculate",
        title: "Expression Draft",
        detail: workspace.expressionInput.trim() || "No expression drafted yet.",
        value: workspace.expressionInput.trim() || "Awaiting input",
        issues: workspace.expressionInput.trim()
          ? []
          : [{ code: "empty-expression", message: "Add an expression to capture a useful snapshot.", severity: "warning" }]
      };
    case "matrix":
      return {
        tool: "matrix",
        title: "Matrix Workspace",
        detail: `Left ${formatMatrixLabel(workspace.matrix.left.rows, workspace.matrix.left.columns)} / Right ${formatMatrixLabel(
          workspace.matrix.right?.rows ?? 2,
          workspace.matrix.right?.columns ?? 2
        )}`,
        value: `Ready for persisted matrix drafts`,
        issues: []
      };
    case "solver":
      return {
        tool: "solver",
        title: "Solver Draft",
        detail: workspace.solver.expression.trim() || "No solver expression drafted yet.",
        value: `${workspace.solver.method} | x0=${workspace.solver.initialGuess}`,
        issues: workspace.solver.expression.trim()
          ? []
          : [{ code: "empty-solver-expression", message: "Add a solver expression before storing a snapshot.", severity: "warning" }]
      };
    case "numerical":
      return {
        tool: "numerical",
        title: "Numerical Draft",
        detail: workspace.numerical.expression.trim() || "No numerical expression drafted yet.",
        value: `${workspace.numerical.tool} | [${workspace.numerical.intervalStart}, ${workspace.numerical.intervalEnd}]`,
        issues: workspace.numerical.expression.trim()
          ? []
          : [{ code: "empty-numerical-expression", message: "Add an expression before storing a numerical snapshot.", severity: "warning" }]
      };
  }
}

export function createHistoryEntry(
  workspace: WorkspaceState,
  settings: CalculatorSettings,
  timestamp: string,
  id: string
): HistoryEntry {
  const presentation = summarizeWorkspace(workspace);

  return {
    id,
    tool: presentation.tool,
    title: presentation.title,
    detail: presentation.detail,
    value: presentation.value,
    createdAt: timestamp,
    mode: buildModeMetadata(settings)
  };
}

export function captureRegister(
  register: MemoryRegister,
  workspace: WorkspaceState,
  settings: CalculatorSettings,
  timestamp: string
): MemoryRegister {
  const presentation = summarizeWorkspace(workspace);

  return {
    ...register,
    value: presentation.value,
    detail: presentation.detail,
    sourceTool: presentation.tool,
    updatedAt: timestamp,
    mode: buildModeMetadata(settings)
  };
}

import { startTransition, useDeferredValue, useEffect, useMemo, useState } from "react";
import type {
  AngleMode,
  CalculatorSettings,
  DisplayMode,
  NumericBackend,
  NumericSettings,
  ResultEnvelope,
  WorkspaceToolId,
  ExpressionResult
} from "@core/contracts";
import {
  createDefaultSettingsDocument,
  createDefaultWorkspaceDocument,
  parsePersistedSettings,
  parsePersistedWorkspace,
  type PersistedSettingsDocument,
  type PersistedWorkspaceDocument
} from "@persistence/schema";
import { clampDisplayPrecision, clampInternalPrecision } from "@core/precision";
import { createCalculationService } from "../../services/calculate";
import "./calculate.css";

const SETTINGS_STORAGE_KEY = "precision-calculator.settings.v1";
const WORKSPACE_STORAGE_KEY = "precision-calculator.workspace.v1";
const calculationService = createCalculationService();

const toolTitles: Record<WorkspaceToolId, string> = {
  calculate: "Expression Engine",
  matrix: "Matrix Lab",
  solver: "Root Solver",
  numerical: "Numerical Tools"
};

type CalculationOutcome = ResultEnvelope<ExpressionResult> | null;

export function CalculateWorkspace() {
  const [settingsDocument, setSettingsDocument] = useState<PersistedSettingsDocument>(loadSettingsDocument);
  const [workspaceDocument, setWorkspaceDocument] = useState<PersistedWorkspaceDocument>(loadWorkspaceDocument);
  const deferredExpression = useDeferredValue(workspaceDocument.payload.expressionInput);
  const deferredSettings = useDeferredValue(settingsDocument.payload);
  const [calculation, setCalculation] = useState<CalculationOutcome>(null);

  useEffect(() => {
    window.localStorage.setItem(SETTINGS_STORAGE_KEY, JSON.stringify(settingsDocument));
  }, [settingsDocument]);

  useEffect(() => {
    window.localStorage.setItem(WORKSPACE_STORAGE_KEY, JSON.stringify(workspaceDocument));
  }, [workspaceDocument]);

  useEffect(() => {
    let cancelled = false;

    if (!deferredExpression.trim()) {
      startTransition(() => {
        setCalculation(null);
      });
      return () => {
        cancelled = true;
      };
    }

    Promise.resolve(
      calculationService.calculate({
        expression: deferredExpression,
        settings: deferredSettings
      })
    ).then((result) => {
      if (cancelled) {
        return;
      }

      startTransition(() => {
        setCalculation(result);
      });
    });

    return () => {
      cancelled = true;
    };
  }, [deferredExpression, deferredSettings]);

  const activeTool = workspaceDocument.payload.activeTool;
  const numericSettings = settingsDocument.payload.numeric;
  const summary = useMemo(
    () =>
      [
        { label: "Backend", value: numericSettings.backend },
        { label: "Display digits", value: String(numericSettings.displayPrecision) },
        { label: "Internal digits", value: String(numericSettings.internalPrecision) },
        { label: "Angle mode", value: numericSettings.angleMode }
      ],
    [numericSettings]
  );

  const updateNumericSettings = <TKey extends keyof NumericSettings>(
    key: TKey,
    value: NumericSettings[TKey]
  ) => {
    setSettingsDocument((current) =>
      stampDocument({
        ...current,
        payload: {
          ...current.payload,
          numeric: {
            ...current.payload.numeric,
            [key]: value
          }
        }
      })
    );
  };

  const updateExpressionInput = (expressionInput: string) => {
    setWorkspaceDocument((current) =>
      stampDocument({
        ...current,
        payload: {
          ...current.payload,
          expressionInput
        }
      })
    );
  };

  const updateActiveTool = (activeToolId: WorkspaceToolId) => {
    setWorkspaceDocument((current) =>
      stampDocument({
        ...current,
        payload: {
          ...current.payload,
          activeTool: activeToolId
        }
      })
    );
  };

  return (
    <main className="app-shell">
      <section className="hero-card">
        <p className="eyebrow">Precision Scientific Calculator</p>
        <h1>Calculation mode with parser, diagnostics, and selectable numeric backends</h1>
        <p className="lede">
          Expression evaluation stays inside a pure tokenizer, parser, compiler, and backend runtime. The
          UI persists numeric settings and workspace input locally so calculation preferences survive restarts.
        </p>
      </section>

      <section className="panel-grid">
        <article className="panel">
          <header className="panel-header">
            <h2>Tool surfaces</h2>
            <span>calculation live</span>
          </header>
          <div className="tool-list">
            {(Object.keys(toolTitles) as WorkspaceToolId[]).map((toolId) => (
              <button
                key={toolId}
                className={toolId === activeTool ? "tool-chip tool-chip-active" : "tool-chip"}
                onClick={() => updateActiveTool(toolId)}
                type="button"
              >
                <strong>{toolTitles[toolId]}</strong>
                <span>{toolId}</span>
              </button>
            ))}
          </div>
        </article>

        <article className="panel">
          <header className="panel-header">
            <h2>Runtime defaults</h2>
            <span>persisted</span>
          </header>
          <dl className="detail-grid">
            {summary.map((item) => (
              <div key={item.label}>
                <dt>{item.label}</dt>
                <dd>{item.value}</dd>
              </div>
            ))}
          </dl>
        </article>
      </section>

      {activeTool === "calculate" ? (
        <CalculatePanel
          calculation={calculation}
          expressionInput={workspaceDocument.payload.expressionInput}
          settings={settingsDocument.payload}
          onExpressionInputChange={updateExpressionInput}
          onNumericSettingsChange={updateNumericSettings}
        />
      ) : (
        <section className="panel">
          <header className="panel-header">
            <h2>{toolTitles[activeTool]}</h2>
            <span>reserved for sibling nodes</span>
          </header>
          <p className="lede">
            This execution node only lands calculation mode. Matrix, solver, and numerical tools keep their
            shell placeholders so later nodes can attach behavior without cross-node refactors.
          </p>
        </section>
      )}
    </main>
  );
}

interface CalculatePanelProps {
  calculation: CalculationOutcome;
  expressionInput: string;
  settings: CalculatorSettings;
  onExpressionInputChange(expression: string): void;
  onNumericSettingsChange<TKey extends keyof NumericSettings>(
    key: TKey,
    value: NumericSettings[TKey]
  ): void;
}

function CalculatePanel(props: CalculatePanelProps) {
  const { calculation, expressionInput, settings, onExpressionInputChange, onNumericSettingsChange } = props;
  const numeric = settings.numeric;

  return (
    <section className="panel calculator-panel">
      <header className="panel-header">
        <h2>Expression Engine</h2>
        <span>{numeric.backend}</span>
      </header>

      <div className="calculator-layout">
        <div className="stack">
          <label className="field-block">
            <span className="field-label">Expression</span>
            <textarea
              className="expression-input"
              onChange={(event) => onExpressionInputChange(event.target.value)}
              placeholder="sin(pi/3)^2 + cos(pi/3)^2"
              rows={5}
              value={expressionInput}
            />
          </label>

          <div className="settings-grid">
            <SelectField
              label="Backend"
              onChange={(value) => onNumericSettingsChange("backend", value as NumericBackend)}
              options={[
                { label: "Float64", value: "float64" },
                { label: "Decimal", value: "decimal" }
              ]}
              value={numeric.backend}
            />
            <SelectField
              label="Angle mode"
              onChange={(value) => onNumericSettingsChange("angleMode", value as AngleMode)}
              options={[
                { label: "Radian", value: "radian" },
                { label: "Degree", value: "degree" }
              ]}
              value={numeric.angleMode}
            />
            <SelectField
              label="Display mode"
              onChange={(value) => onNumericSettingsChange("displayMode", value as DisplayMode)}
              options={[
                { label: "Normal", value: "normal" },
                { label: "Scientific", value: "scientific" },
                { label: "Engineering", value: "engineering" }
              ]}
              value={numeric.displayMode}
            />
            <NumberField
              label="Display digits"
              max={32}
              min={1}
              onChange={(value) =>
                onNumericSettingsChange("displayPrecision", clampDisplayPrecision(value))
              }
              step={1}
              value={numeric.displayPrecision}
            />
            <NumberField
              label="Internal digits"
              max={128}
              min={8}
              onChange={(value) =>
                onNumericSettingsChange("internalPrecision", clampInternalPrecision(value))
              }
              step={1}
              value={numeric.internalPrecision}
            />
            <NumberField
              label="Solver tolerance"
              max={1}
              min={1e-16}
              onChange={(value) => onNumericSettingsChange("solverTolerance", sanitizePositive(value, 1e-10))}
              step={1e-10}
              value={numeric.solverTolerance}
            />
            <NumberField
              label="Max iterations"
              max={100000}
              min={1}
              onChange={(value) => onNumericSettingsChange("maxIterations", sanitizeInteger(value, 100))}
              step={1}
              value={numeric.maxIterations}
            />
          </div>
        </div>

        <div className="stack">
          <div className="result-card">
            <p className="result-label">Formatted result</p>
            <output className="result-value">
              {calculation?.ok ? calculation.value.formattedValue : expressionInput.trim() ? "Error" : "Ready"}
            </output>
            <p className="result-meta">
              {calculation?.ok
                ? `Approximation ${formatApproximation(calculation.value.approximateValue)}`
                : "Live diagnostics update as the expression changes."}
            </p>
          </div>

          <div className="result-grid">
            <div className="result-box">
              <span>Canonical</span>
              <strong>{calculation?.ok ? calculation.value.canonicalExpression : "n/a"}</strong>
            </div>
            <div className="result-box">
              <span>Elapsed</span>
              <strong>{formatElapsedMs(calculation?.metadata.elapsedMs)}</strong>
            </div>
            <div className="result-box">
              <span>Backend</span>
              <strong>{calculation?.metadata.backend ?? numeric.backend}</strong>
            </div>
            <div className="result-box">
              <span>Status</span>
              <strong>{calculation?.ok ? "ok" : calculation ? "diagnostic" : "idle"}</strong>
            </div>
          </div>

          <div className="issue-list">
            {(calculation?.issues ?? []).length > 0 ? (
              (calculation?.issues ?? []).map((issue) => (
                <div className={issue.severity === "error" ? "issue issue-error" : "issue"} key={`${issue.code}-${issue.message}`}>
                  <strong>{issue.code}</strong>
                  <span>{issue.message}</span>
                </div>
              ))
            ) : (
              <div className="issue issue-neutral">
                <strong>Examples</strong>
                <span>Try `sin(pi/3)^2 + cos(pi/3)^2`, `sqrt(2)^2 - 2`, or `sin(90)` in degree mode.</span>
              </div>
            )}
          </div>
        </div>
      </div>
    </section>
  );
}

interface SelectFieldProps {
  label: string;
  options: Array<{ label: string; value: string }>;
  value: string;
  onChange(value: string): void;
}

function SelectField(props: SelectFieldProps) {
  return (
    <label className="field-block">
      <span className="field-label">{props.label}</span>
      <select className="field-control" onChange={(event) => props.onChange(event.target.value)} value={props.value}>
        {props.options.map((option) => (
          <option key={option.value} value={option.value}>
            {option.label}
          </option>
        ))}
      </select>
    </label>
  );
}

interface NumberFieldProps {
  label: string;
  min: number;
  max: number;
  step: number;
  value: number;
  onChange(value: number): void;
}

function NumberField(props: NumberFieldProps) {
  return (
    <label className="field-block">
      <span className="field-label">{props.label}</span>
      <input
        className="field-control"
        max={props.max}
        min={props.min}
        onChange={(event) => props.onChange(Number(event.target.value))}
        step={props.step}
        type="number"
        value={props.value}
      />
    </label>
  );
}

function loadSettingsDocument(): PersistedSettingsDocument {
  const fallback = createDefaultSettingsDocument();

  try {
    const raw = window.localStorage.getItem(SETTINGS_STORAGE_KEY);
    if (!raw) {
      return fallback;
    }

    return parsePersistedSettings(JSON.parse(raw)) ?? fallback;
  } catch {
    return fallback;
  }
}

function loadWorkspaceDocument(): PersistedWorkspaceDocument {
  const fallback = createDefaultWorkspaceDocument();

  try {
    const raw = window.localStorage.getItem(WORKSPACE_STORAGE_KEY);
    if (!raw) {
      return fallback;
    }

    return parsePersistedWorkspace(JSON.parse(raw)) ?? fallback;
  } catch {
    return fallback;
  }
}

function stampDocument<TDocument extends { updatedAt: string }>(document: TDocument): TDocument {
  return {
    ...document,
    updatedAt: new Date().toISOString()
  };
}

function sanitizePositive(value: number, fallback: number): number {
  return Number.isFinite(value) && value > 0 ? value : fallback;
}

function sanitizeInteger(value: number, fallback: number): number {
  return Number.isFinite(value) && value > 0 ? Math.trunc(value) : fallback;
}

function formatApproximation(value: number | null): string {
  if (value === null) {
    return "n/a";
  }

  return Number.isFinite(value) ? value.toPrecision(12) : String(value);
}

function formatElapsedMs(value: number | undefined): string {
  if (value === undefined) {
    return "n/a";
  }

  return `${value.toFixed(3)} ms`;
}

import type { CalculatorSettings, MatrixData, WorkspaceState } from "@core/contracts";
import type { HistoryEntry, HistoryModeMetadata } from "../features/history/model";
import type { MemoryRegister } from "../features/memory/model";
import { createDefaultMemoryRegisters } from "../features/memory/model";
import { createDefaultWorkspaceState, sanitizeWorkspaceState } from "../app/workspaceDrafts";
import { createDefaultCalculatorSettings, sanitizeCalculatorSettings } from "../features/settings/model";

export const SETTINGS_SCHEMA_VERSION = 1 as const;
export const WORKSPACE_SCHEMA_VERSION = 1 as const;
export const HISTORY_SCHEMA_VERSION = 1 as const;
export const MEMORY_SCHEMA_VERSION = 1 as const;

export interface VersionedDocument<TVersion extends number, TPayload> {
  version: TVersion;
  payload: TPayload;
  updatedAt: string;
}

export type PersistedSettingsDocument = VersionedDocument<typeof SETTINGS_SCHEMA_VERSION, CalculatorSettings>;
export type PersistedWorkspaceDocument = VersionedDocument<typeof WORKSPACE_SCHEMA_VERSION, WorkspaceState>;
export type PersistedHistoryDocument = VersionedDocument<typeof HISTORY_SCHEMA_VERSION, { entries: HistoryEntry[] }>;
export type PersistedMemoryDocument = VersionedDocument<typeof MEMORY_SCHEMA_VERSION, { registers: MemoryRegister[] }>;

const DEFAULT_UPDATED_AT = new Date(0).toISOString();

export function createDefaultSettingsDocument(): PersistedSettingsDocument {
  return {
    version: SETTINGS_SCHEMA_VERSION,
    updatedAt: DEFAULT_UPDATED_AT,
    payload: createDefaultCalculatorSettings()
  };
}

export function createDefaultWorkspaceDocument(): PersistedWorkspaceDocument {
  return {
    version: WORKSPACE_SCHEMA_VERSION,
    updatedAt: DEFAULT_UPDATED_AT,
    payload: createDefaultWorkspaceState()
  };
}

export function createDefaultHistoryDocument(): PersistedHistoryDocument {
  return {
    version: HISTORY_SCHEMA_VERSION,
    updatedAt: DEFAULT_UPDATED_AT,
    payload: {
      entries: []
    }
  };
}

export function createDefaultMemoryDocument(): PersistedMemoryDocument {
  return {
    version: MEMORY_SCHEMA_VERSION,
    updatedAt: DEFAULT_UPDATED_AT,
    payload: {
      registers: createDefaultMemoryRegisters()
    }
  };
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function isMatrixData(value: unknown): value is MatrixData {
  if (!isRecord(value)) {
    return false;
  }

  return (
    typeof value.rows === "number" &&
    typeof value.columns === "number" &&
    Array.isArray(value.values) &&
    value.values.every(
      (row) => Array.isArray(row) && row.every((entry) => typeof entry === "number")
    )
  );
}

function isCalculatorSettings(value: unknown): value is CalculatorSettings {
  if (!isRecord(value) || !isRecord(value.numeric)) {
    return false;
  }

  const numeric = value.numeric;

  return (
    (numeric.backend === "float64" || numeric.backend === "decimal") &&
    typeof numeric.displayPrecision === "number" &&
    typeof numeric.internalPrecision === "number" &&
    typeof numeric.solverTolerance === "number" &&
    typeof numeric.maxIterations === "number" &&
    (numeric.angleMode === "degree" || numeric.angleMode === "radian") &&
    (numeric.displayMode === "normal" ||
      numeric.displayMode === "scientific" ||
      numeric.displayMode === "engineering") &&
    typeof value.locale === "string"
  );
}

function isHistoryModeMetadata(value: unknown): value is HistoryModeMetadata {
  return (
    isRecord(value) &&
    (value.backend === "float64" || value.backend === "decimal") &&
    (value.angleMode === "degree" || value.angleMode === "radian") &&
    (value.displayMode === "normal" || value.displayMode === "scientific" || value.displayMode === "engineering") &&
    typeof value.displayPrecision === "number"
  );
}

function isHistoryEntry(value: unknown): value is HistoryEntry {
  return (
    isRecord(value) &&
    typeof value.id === "string" &&
    (value.tool === "calculate" || value.tool === "matrix" || value.tool === "solver" || value.tool === "numerical") &&
    typeof value.title === "string" &&
    typeof value.detail === "string" &&
    typeof value.value === "string" &&
    typeof value.createdAt === "string" &&
    isHistoryModeMetadata(value.mode)
  );
}

function isMemoryRegister(value: unknown): value is MemoryRegister {
  return (
    isRecord(value) &&
    typeof value.id === "string" &&
    typeof value.label === "string" &&
    typeof value.value === "string" &&
    typeof value.detail === "string" &&
    (value.sourceTool === null ||
      value.sourceTool === "calculate" ||
      value.sourceTool === "matrix" ||
      value.sourceTool === "solver" ||
      value.sourceTool === "numerical") &&
    (value.updatedAt === null || typeof value.updatedAt === "string") &&
    (value.mode === null || isHistoryModeMetadata(value.mode))
  );
}

function isWorkspaceState(value: unknown): value is WorkspaceState {
  if (!isRecord(value) || !isRecord(value.matrix) || !isRecord(value.solver) || !isRecord(value.numerical)) {
    return false;
  }

  return (
    (value.activeTool === "calculate" ||
      value.activeTool === "matrix" ||
      value.activeTool === "solver" ||
      value.activeTool === "numerical") &&
    typeof value.expressionInput === "string" &&
    isMatrixData(value.matrix.left) &&
    (!("right" in value.matrix) || value.matrix.right === undefined || isMatrixData(value.matrix.right)) &&
    typeof value.solver.expression === "string" &&
    (value.solver.method === "newton" || value.solver.method === "bisection") &&
    typeof value.solver.initialGuess === "string" &&
    typeof value.solver.bracketLower === "string" &&
    typeof value.solver.bracketUpper === "string" &&
    typeof value.numerical.expression === "string" &&
    (value.numerical.tool === "differentiate" ||
      value.numerical.tool === "integrate" ||
      value.numerical.tool === "sample") &&
    typeof value.numerical.point === "string" &&
    typeof value.numerical.intervalStart === "string" &&
    typeof value.numerical.intervalEnd === "string"
  );
}

export function parsePersistedSettings(value: unknown): PersistedSettingsDocument | null {
  if (!isRecord(value) || value.version !== SETTINGS_SCHEMA_VERSION || !isCalculatorSettings(value.payload)) {
    return null;
  }

  return {
    version: SETTINGS_SCHEMA_VERSION,
    updatedAt: typeof value.updatedAt === "string" ? value.updatedAt : DEFAULT_UPDATED_AT,
    payload: sanitizeCalculatorSettings(value.payload)
  };
}

export function parsePersistedWorkspace(value: unknown): PersistedWorkspaceDocument | null {
  if (!isRecord(value) || value.version !== WORKSPACE_SCHEMA_VERSION || !isWorkspaceState(value.payload)) {
    return null;
  }

  return {
    version: WORKSPACE_SCHEMA_VERSION,
    updatedAt: typeof value.updatedAt === "string" ? value.updatedAt : DEFAULT_UPDATED_AT,
    payload: sanitizeWorkspaceState(value.payload)
  };
}

export function parsePersistedHistory(value: unknown): PersistedHistoryDocument | null {
  if (
    !isRecord(value) ||
    value.version !== HISTORY_SCHEMA_VERSION ||
    !isRecord(value.payload) ||
    !Array.isArray(value.payload.entries) ||
    !value.payload.entries.every((entry) => isHistoryEntry(entry))
  ) {
    return null;
  }

  return {
    version: HISTORY_SCHEMA_VERSION,
    updatedAt: typeof value.updatedAt === "string" ? value.updatedAt : DEFAULT_UPDATED_AT,
    payload: {
      entries: value.payload.entries
    }
  };
}

export function parsePersistedMemory(value: unknown): PersistedMemoryDocument | null {
  if (
    !isRecord(value) ||
    value.version !== MEMORY_SCHEMA_VERSION ||
    !isRecord(value.payload) ||
    !Array.isArray(value.payload.registers) ||
    !value.payload.registers.every((register) => isMemoryRegister(register))
  ) {
    return null;
  }

  return {
    version: MEMORY_SCHEMA_VERSION,
    updatedAt: typeof value.updatedAt === "string" ? value.updatedAt : DEFAULT_UPDATED_AT,
    payload: {
      registers: value.payload.registers
    }
  };
}

