import { createDefaultSettingsDocument } from "@persistence/schema";
import { createMatrixService } from "./service";

const settings = createDefaultSettingsDocument().payload;

describe("matrix service", () => {
  it("returns explicit failures for incompatible matrix dimensions", async () => {
    const service = createMatrixService();
    const result = await Promise.resolve(
      service.evaluate({
        operation: "add",
        left: {
          rows: 2,
          columns: 2,
          values: [
            [1, 2],
            [3, 4]
          ]
        },
        right: {
          rows: 2,
          columns: 3,
          values: [
            [1, 2, 3],
            [4, 5, 6]
          ]
        },
        settings
      })
    );

    expect(result.ok).toBe(false);
    expect(result.issues[0]?.code).toBe("matrix_dimension_mismatch");
  });

  it("formats determinant results and carries pivot diagnostics", async () => {
    const service = createMatrixService();
    const result = await Promise.resolve(
      service.evaluate({
        operation: "determinant",
        left: {
          rows: 2,
          columns: 2,
          values: [
            [4, 6],
            [3, 8]
          ]
        },
        settings
      })
    );

    expect(result.ok).toBe(true);
    if (!result.ok) {
      return;
    }

    expect(result.value.scalar).toBe("14");
    expect(result.value.diagnostics?.pivotStrategy).toBe("partial");
  });

  it("reports singular systems through failed result envelopes", async () => {
    const service = createMatrixService();
    const result = await Promise.resolve(
      service.solveLinearSystem({
        matrix: {
          rows: 2,
          columns: 2,
          values: [
            [1, 2],
            [2, 4]
          ]
        },
        rightHandSide: [1, 2],
        settings
      })
    );

    expect(result.ok).toBe(false);
    expect(result.issues[0]?.code).toBe("matrix_singular");
  });
});

import { describe, expect, it } from "vitest";
import type { CalculatorSettings } from "@core/contracts";
import { parseTokens, tokenizeExpression } from "@core/expression";
import { createDefaultSettingsDocument } from "@persistence/schema";
import { createCalculationService } from "../../src/services/calculate";

function makeSettings(overrides?: Partial<CalculatorSettings["numeric"]>): CalculatorSettings {
  return {
    ...createDefaultSettingsDocument().payload,
    numeric: {
      ...createDefaultSettingsDocument().payload.numeric,
      ...overrides
    }
  };
}

describe("expression engine", () => {
  it("tokenizes scientific notation and parses nested expressions", () => {
    const tokenized = tokenizeExpression("1.2e-12 + sqrt(2)");
    const parsed = parseTokens(tokenized.tokens);

    expect(tokenized.issues).toEqual([]);
    expect(tokenized.tokens.map((token) => token.type)).toEqual([
      "number",
      "plus",
      "identifier",
      "leftParen",
      "number",
      "rightParen",
      "eof"
    ]);
    expect(parsed.issues).toEqual([]);
    expect(parsed.ast).toMatchObject({
      kind: "binary",
      operator: "+"
    });
  });

  it("evaluates function-rich identities correctly", async () => {
    const service = createCalculationService();
    const result = await service.calculate({
      expression: "sin(pi/3)^2 + cos(pi/3)^2",
      settings: makeSettings()
    });

    expect(result.ok).toBe(true);
    if (result.ok) {
      expect(result.value.canonicalExpression).toBe("sin(pi / 3) ^ 2 + cos(pi / 3) ^ 2");
      expect(result.value.approximateValue).toBeCloseTo(1, 12);
    }
  });

  it("returns structured diagnostics for invalid expressions", async () => {
    const service = createCalculationService();
    const result = await service.calculate({
      expression: "sin(",
      settings: makeSettings()
    });

    expect(result.ok).toBe(false);
    if (!result.ok) {
      expect(result.issues[0]).toMatchObject({
        code: "expression.expected_operand",
        severity: "error",
        field: "expression"
      });
    }
  });

  it("resolves user variables through the compiled evaluator", async () => {
    const service = createCalculationService();
    const result = await service.calculate({
      expression: "gain * exp(offset)",
      settings: makeSettings(),
      variables: {
        gain: 3,
        offset: "1"
      }
    });

    expect(result.ok).toBe(true);
    if (result.ok) {
      expect(result.value.approximateValue).toBeCloseTo(3 * Math.E, 12);
    }
  });
});

import type { AngleMode, CalculatorSettings, DisplayMode, NumericBackend } from "@core/contracts";

export const BACKEND_OPTIONS: NumericBackend[] = ["float64", "decimal"];
export const ANGLE_MODE_OPTIONS: AngleMode[] = ["radian", "degree"];
export const DISPLAY_MODE_OPTIONS: DisplayMode[] = ["normal", "scientific", "engineering"];

export const SETTINGS_LIMITS = {
  displayPrecision: { min: 2, max: 24 },
  internalPrecision: { min: 16, max: 128 },
  solverTolerance: { min: 1e-15, max: 1e-3 },
  maxIterations: { min: 5, max: 1000 }
} as const;

export function createDefaultCalculatorSettings(): CalculatorSettings {
  return {
    numeric: {
      backend: "float64",
      displayPrecision: 12,
      internalPrecision: 28,
      solverTolerance: 1e-10,
      maxIterations: 100,
      angleMode: "radian",
      displayMode: "normal"
    },
    locale: "en-US"
  };
}

export function clampInteger(value: number, minimum: number, maximum: number): number {
  if (!Number.isFinite(value)) {
    return minimum;
  }

  return Math.min(maximum, Math.max(minimum, Math.round(value)));
}

export function clampNumber(value: number, minimum: number, maximum: number): number {
  if (!Number.isFinite(value)) {
    return minimum;
  }

  return Math.min(maximum, Math.max(minimum, value));
}

export function sanitizeCalculatorSettings(settings: CalculatorSettings): CalculatorSettings {
  const defaults = createDefaultCalculatorSettings();

  return {
    locale: settings.locale.trim() || defaults.locale,
    numeric: {
      backend: BACKEND_OPTIONS.includes(settings.numeric.backend) ? settings.numeric.backend : defaults.numeric.backend,
      displayPrecision: clampInteger(
        settings.numeric.displayPrecision,
        SETTINGS_LIMITS.displayPrecision.min,
        SETTINGS_LIMITS.displayPrecision.max
      ),
      internalPrecision: clampInteger(
        settings.numeric.internalPrecision,
        SETTINGS_LIMITS.internalPrecision.min,
        SETTINGS_LIMITS.internalPrecision.max
      ),
      solverTolerance: clampNumber(
        settings.numeric.solverTolerance,
        SETTINGS_LIMITS.solverTolerance.min,
        SETTINGS_LIMITS.solverTolerance.max
      ),
      maxIterations: clampInteger(
        settings.numeric.maxIterations,
        SETTINGS_LIMITS.maxIterations.min,
        SETTINGS_LIMITS.maxIterations.max
      ),
      angleMode: ANGLE_MODE_OPTIONS.includes(settings.numeric.angleMode)
        ? settings.numeric.angleMode
        : defaults.numeric.angleMode,
      displayMode: DISPLAY_MODE_OPTIONS.includes(settings.numeric.displayMode)
        ? settings.numeric.displayMode
        : defaults.numeric.displayMode
    }
  };
}

import type { ReactNode } from "react";
import type { ComputationIssue } from "@core/contracts";

interface MetadataItem {
  label: string;
  value: string;
}

interface ResultPanelProps {
  eyebrow: string;
  title: string;
  value: string;
  detail: string;
  issues: ComputationIssue[];
  metadata: MetadataItem[];
  children?: ReactNode;
}

export function ResultPanel({ eyebrow, title, value, detail, issues, metadata, children }: ResultPanelProps) {
  return (
    <section className="panel result-panel">
      <header className="panel-header">
        <div>
          <p className="eyebrow">{eyebrow}</p>
          <h2>{title}</h2>
        </div>
        <span>{issues.length === 0 ? "ready" : `${issues.length} alert${issues.length === 1 ? "" : "s"}`}</span>
      </header>
      <div className="result-value">{value}</div>
      <p className="result-detail">{detail}</p>
      <dl className="meta-grid">
        {metadata.map((item) => (
          <div key={item.label}>
            <dt>{item.label}</dt>
            <dd>{item.value}</dd>
          </div>
        ))}
      </dl>
      {issues.length > 0 ? (
        <ul className="issue-list">
          {issues.map((issue) => (
            <li key={issue.code}>
              <strong>{issue.severity}</strong>
              <span>{issue.message}</span>
            </li>
          ))}
        </ul>
      ) : null}
      {children ? <div className="result-actions">{children}</div> : null}
    </section>
  );
}

